  office:["Blazer","Oversized Blazer","Trench Coat","Wool Coat","Trousers","Wide-Leg Trousers","Pencil Skirt","Bodysuit","Oxford Shirt","Button-Down","Blazer Dress"],
  party:["Sequin Dress","Corset Top","Bustier","Bodycon Dress","Satin Skirt","Mini Dress","Tube Top"],
  casual:["T-Shirt","Jeans (Straight)","Jeans (Wide Leg)","Denim Jacket","Shirt","Linen Shirt"],
  coffee_date:["Wrap Dress","Midi Dress","Wrap Top","Knit Top","Midi Skirt","A-Line Skirt","Cardigan"],
  date_night:["Slip Dress","Bodycon Dress","Corset Top","Leather Skirt","Satin Skirt","Leather Jacket"],
  summer_picnic:["Floral Dress","Sundress","Romper","Linen Shirt","Shorts","Denim Shorts","Floral Skirt"],
  streetwear:["Cargo Pants","Hoodie","Graphic Tee","Bomber Jacket","Leather Jacket","Biker Shorts","Varsity Jacket","Chunky Sneakers"],
  minimalist:["Trench Coat","Turtleneck","Wide-Leg Trousers","Blazer Dress","Knit Dress","Slip Dress"],
  feminine:["Floral Dress","Midi Dress","Wrap Dress","Off-Shoulder Top","Wrap Top","Midi Skirt","Floral Skirt","A-Line Skirt"],
