    Outerwear:<svg width={s} height={s} viewBox="0 0 32 32" fill="none"><path d="M6 8L2 14H8V28H14V18H18V28H24V14H30L26 8L18 11V8H14V11L6 8Z" fill={c} opacity=".9"/></svg>,
    Shoes:<svg width={s} height={s} viewBox="0 0 32 32" fill="none"><path d="M4 20C4 20 6 14 10 13L22 14L28 18V22H4V20Z" fill={c} opacity=".9"/></svg>,
