    Accessory:<svg width={s} height={s} viewBox="0 0 32 32" fill="none"><circle cx="16" cy="16" r="8" stroke={c} strokeWidth="3" opacity=".9"/><circle cx="16" cy="16" r="3" fill={c} opacity=".9"/></svg>,
